from Bio.PDB import PDBParser
from Bio.SeqUtils import seq1
from Bio import pairwise2
import requests, io, itertools
parser=PDBParser(QUIET=True)
def chains(pdb):
    text=requests.get(f'https://files.rcsb.org/download/{pdb}.pdb',timeout=30).text
    structure=parser.get_structure(pdb, io.StringIO(text))
    out={}
    for chain in structure[0]:
        seq=[]
        for res in chain:
            if res.id[0]!=' ': continue
            try: seq.append(seq1(res.resname))
            except: seq.append('X')
        out[chain.id]=''.join(seq)
    return out
s1=chains('3OP5'); s2=chains('2V62')
for c1,seq1s in s1.items():
    for c2,seq2s in s2.items():
        al=pairwise2.align.globalxx(seq1s,seq2s,one_alignment_only=True)[0]
        ident=sum((a==b and a!='-') for a,b in zip(al.seqA,al.seqB))
        aligned=sum((a!='-' and b!='-') for a,b in zip(al.seqA,al.seqB))
        print(c1,c2,'lens',len(seq1s),len(seq2s),'ident',ident,'aligned',aligned,'frac',ident/aligned if aligned else 0)
